SELECT * FROM dashboard_conversation_turn 
WHERE (system_turn = 0 OR system_turn IS NULL)


    
        AND employee_id = #{userId}
    
    
        AND employee_id LIKE CONCAT('%', #{userIdLike}, '%')
    



    AND start_time >= #{startTime}


    AND start_time <= #{endTime}

ORDER BY start_time DESC

SELECT COUNT(*) FROM dashboard_conversation_turn t

    INNER JOIN dashboard_employee e ON t.employee_id = e.employee_id

WHERE (system_turn = 0 OR system_turn IS NULL)

    AND e.team_name = #{teamName}


    AND t.employee_id = #{userId}


    AND t.start_time >= #{startTime}


    AND t.start_time <= #{endTime}

SELECT COUNT(*) FROM dashboard_conversation_turn t

    INNER JOIN dashboard_employee e ON t.employee_id = e.employee_id

WHERE (system_turn = 0 OR system_turn IS NULL)
  AND is_complete = 1
  AND has_error = 0

    AND e.team_name = #{teamName}


    AND t.employee_id = #{userId}


    AND t.start_time >= #{startTime}


    AND t.start_time <= #{endTime}

SELECT COUNT(*) FROM dashboard_conversation_turn
WHERE scan_id = #{scanId}
  AND (system_turn = 0 OR system_turn IS NULL)
